class Solution:
    def subArrayRanges(self, nums):
        n = len(nums)
        total = 0
        for i in range(n):
            mn = mx = nums[i]
            for j in range(i, n):
                if nums[j] < mn:
                    mn = nums[j]
                if nums[j] > mx:
                    mx = nums[j]
                total += mx - mn
        return total

