class Solution:
    def subArrayRanges(self, nums):
        n = len(nums)

        def sum_of_extrema(is_max):
            left = [0] * n
            right = [0] * n
            stack = []
            for i in range(n):
                while stack and (nums[stack[-1]] < nums[i] if is_max else nums[stack[-1]] > nums[i]):
                    stack.pop()
                left[i] = i - stack[-1] if stack else i + 1
                stack.append(i)
            stack = []
            for i in range(n - 1, -1, -1):
                while stack and (nums[stack[-1]] <= nums[i] if is_max else nums[stack[-1]] >= nums[i]):
                    stack.pop()
                right[i] = stack[-1] - i if stack else n - i
                stack.append(i)
            total = 0
            for i in range(n):
                total += nums[i] * left[i] * right[i]
            return total

        return sum_of_extrema(True) - sum_of_extrema(False)

