var subArrayRanges = function(nums) {
    const n = nums.length;

    function sumOfExtrema(isMax) {
        const left = new Array(n).fill(0);
        const right = new Array(n).fill(0);
        let stack = [];
        for (let i = 0; i < n; i++) {
            while (stack.length && (isMax ? nums[stack[stack.length - 1]] < nums[i] : nums[stack[stack.length - 1]] > nums[i])) {
                stack.pop();
            }
            left[i] = stack.length ? i - stack[stack.length - 1] : i + 1;
            stack.push(i);
        }
        stack = [];
        for (let i = n - 1; i >= 0; i--) {
            while (stack.length && (isMax ? nums[stack[stack.length - 1]] <= nums[i] : nums[stack[stack.length - 1]] >= nums[i])) {
                stack.pop();
            }
            right[i] = stack.length ? stack[stack.length - 1] - i : n - i;
            stack.push(i);
        }
        let total = 0;
        for (let i = 0; i < n; i++) total += nums[i] * left[i] * right[i];
        return total;
    }

    return sumOfExtrema(true) - sumOfExtrema(false);
};
